#include<bits/stdc++.h>
using namespace std;
long long n,m;
vector<pair<long long,long long>> mp[100010];
long long ans=0;
long long dfs(long long x,long long k,long long fa=-1)
{
    multiset<long long> s;
    for(auto i:mp[x])
    {
        long long v=i.first,val=i.second;
        if(v!=fa)
        {
            long long tmp=dfs(v,k,x)+val;
            if(tmp>=k)
            {
                ans++;
            }
            else
            {
                s.insert(tmp);
            }
        }
    }
    long long max1=0;
    while(!s.empty())
    {
        if(s.size()==1)
        {
            max1=max(max1,(*s.begin()));
            break;
        }
        auto it=s.lower_bound(k-(*s.begin()));
        if(it==s.begin()&&s.count(*it)==1)
        {
            it++;
        }
        if(it==s.end())
        {
            max1=max(max1,(*s.begin()));
            s.erase(s.begin());
        }
        else
        {
            ans++;
            s.erase(it);
            s.erase(s.begin());
        }
    }
    return max1;
}
bool check(long long x)
{
    ans=0;
    dfs(1,x);
    return ans>=m;
}
int main()
{
    // freopen("C:\\Users\\lifei\\Downloads\\P5021_5.in","r",stdin);
    scanf("%lld%lld",&n,&m);
    for(long long i=1;i<n;i++)
    {
        long long u,v,w;
        scanf("%lld%lld%lld",&u,&v,&w);
        mp[u].push_back(make_pair(v,w));
        mp[v].push_back(make_pair(u,w));
    }
    long long l=0,r=1e12,best;
    while(l<=r)
    {
        long long mid=(l+r)/2;
        if(check(mid))
        {
            l=mid+1;
            best=mid;
        }
        else
        {
            r=mid-1;
        }
    }
    printf("%lld",best);
    return 0;
}
